#include<bits/stdc++.h>
using namespace std;
const int N=(1<<20),mod=998244353;
int n,f[N],g[N];
long long s[N];
int lowbit(int x)
{
    return x&-x;
}
int main()
{
    scanf("%d",&n);
    g[0]=1;
    for(int i=0;i<n;i++)
    {
        scanf("%lld",&s[1<<i]);
        f[1<<i]=1;
    }
    for(int i=0;i<(1<<n);i++)
    {
        s[i]=s[lowbit(i)]+s[i^lowbit(i)];
    }
    for(int i=1;i<(1<<n);i++)
    {
        if(s[i]<0)
        {
            for(int j=0;j<n;j++)
            {
                if(i&(1<<j))
                {
                    g[i]+=g[i^(1<<j)];
                    g[i]%=mod;
                }
            }
        }
        else
        {
            for(int j=0;j<n;j++)
            {
                if(!(i&(1<<j)))
                {
                    f[i|(1<<j)]+=f[i];
                    f[i|(1<<j)]%=mod;
                }
            }
        }
    }
    long long ans=0;
    for(int i=1;i<(1<<n);i++)
    {
        ans+=s[i]%mod*f[i]%mod*g[((1<<n)-1)^i]%mod;
        ans%=mod;
    }
    printf("%lld",(ans+mod)%mod);
    return 0;
}
